import{_ as o,o as t,c as n,ae as a}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Web Troubleshooting","description":"","frontmatter":{"title":"Web Troubleshooting","slug":"web-troubleshooting"},"headers":[],"relativePath":"developer-hub/web-troubleshooting.md","filePath":"developer-hub/web-troubleshooting.md"}'),i={name:"developer-hub/web-troubleshooting.md"};function r(s,e,l,c,h,d){return t(),n("div",null,[...e[0]||(e[0]=[a('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This guide lists out some of the most common challenges we see customers run into when trying to integrate the Branch Web SDK.</p><p>To integrate the Branch Web SDK, follow the steps in our Web SDK Basic Integration <a href="./web-basic-integration.html">guide</a>.</p><h2 id="scenarios" tabindex="-1">Scenarios <a class="header-anchor" href="#scenarios" aria-label="Permalink to &quot;Scenarios&quot;">​</a></h2><h3 id="journeys-banner-not-sticking-to-nav" tabindex="-1">Journeys Banner Not Sticking to Nav <a class="header-anchor" href="#journeys-banner-not-sticking-to-nav" aria-label="Permalink to &quot;Journeys Banner Not Sticking to Nav&quot;">​</a></h3><p>If your Journeys banner is not sticking to your nav bar:</p><ol><li>Navigate to the Journeys <a href="https://dashboard.branch.io/web/journeys" target="_blank" rel="noreferrer">section</a> of the Branch Dashboard.</li><li>Select <strong>Journey</strong> → <strong>Edit</strong> → <strong>Configure Views</strong> → <strong>Banner</strong> → <strong>Page Placement</strong>.</li><li>Set the banner scroll value to <code>sticky</code>. Hit <strong>Save</strong>.</li><li>Add the following div to your navigation:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;div class=&quot;branch-journeys-top&quot;&gt;&lt;/div&gt;</span></span></code></pre></div><h3 id="access-control-allow-origin-error" tabindex="-1">Access-Control-Allow-Origin Error <a class="header-anchor" href="#access-control-allow-origin-error" aria-label="Permalink to &quot;Access-Control-Allow-Origin Error&quot;">​</a></h3><p>Below is a possible error message you may see:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>XMLHttpRequest cannot load https://api2.branch.io/v1/open. No &#39;Access-Control-Allow-Origin&#39; header is present on the requested resource. Origin &#39;null&#39; is therefore not allowed access. The response had HTTP status code 400.</span></span></code></pre></div><p>If you see this error message, make sure the Branch Key (live or test) is the same between the Branch Deep Link and your website.</p><h3 id="content-security-policy-violations" tabindex="-1">Content Security Policy Violations <a class="header-anchor" href="#content-security-policy-violations" aria-label="Permalink to &quot;Content Security Policy Violations&quot;">​</a></h3><p>If you are running into content security policy violations:</p><ol><li>Generate a dynamic nonce value.</li><li>Include the nonce value as a <code>script-src</code> and <code>style-src</code> exception within your Content Security Policy.</li><li>Pass the nonce value to the <code>init()</code> method:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>branch.init(YOUR_BRANCH_KEY, {&#39;nonce&#39;: &#39;GENERATED_NONCE_VALUE&#39; });</span></span></code></pre></div><h3 id="blocked-by-client-error" tabindex="-1">Blocked By Client Error <a class="header-anchor" href="#blocked-by-client-error" aria-label="Permalink to &quot;Blocked By Client Error&quot;">​</a></h3><p>If you run into the error <code>ERR_BLOCKED_BY_CLIENT</code>, you can try changing the host of the Branch Web SDK from <code>https://cdn.branch.io</code> to your own personal hosting solution.</p><p>To do this, change <code>src=&quot;https://cdn.branch.io/branch-latest.min.js&quot;</code> within the <a href="./web-basic-integration.html#script-tag-in-html">script tag</a> in your HTML to point to a location you own. That location needs to contain the <code>.js</code> file corresponding to the version of Branch you want to use (<code>branch-latest</code> or alternatively, a specific version like <code>branch-2.85.0</code>).</p><p>For the CDN link, SRI hash, and initialization script, visit the Web Version History <a href="./web-version-history.html">page</a>.</p>',20)])])}const b=o(i,[["render",r]]);export{p as __pageData,b as default};
